const Dropdown=()=>{const dropdowns=document.querySelectorAll(".dropdown");if(!dropdowns.length)return;document.addEventListener("keydown",e=>{"Escape"===e.key&&dropdowns.forEach(dropdown=>{dropdown.removeAttribute("open")})}),document.addEventListener("click",e=>{dropdowns.forEach(dropdown=>{if(!dropdown.open)return;const body=dropdown.querySelector(".dropdown__body");if(!body)return;const clickedInsideBody=body.contains(e.target),clickedSummary=dropdown.querySelector("summary")?.contains(e.target);clickedInsideBody||clickedSummary||dropdown.removeAttribute("open")})})},Form=()=>{document.querySelectorAll(".form-control-action[data-reveal]").forEach(btn=>{const input=btn.closest(".form-group").querySelector(".form-control"),revealed=()=>"text"===input.type;btn.addEventListener("click",()=>{input.type=revealed()?"password":"text",btn.dataset.reveal=revealed()?"on":"off"})})};function init(){Dropdown(),Form(),function(){const input=document.getElementById("code"),btn=document.getElementById("submit-btn");input&&btn&&input.addEventListener("input",()=>btn.disabled=""===input.value)}()}document.addEventListener("DOMContentLoaded",init);